SELECT
    LIC_NAME,	LIC_ORG,		MIKEP_DOC_NO,	TO_CHAR(LIC_DATE, 'YYYY-MM-DD') AS LIC_DATE,
    PIC_NAME,	PIC_POS,		PIC_TEL,		PIC_EMAIL,		AFTER_TASK,
    REGI_DATE,	INWRITER_ID,	UPDATE_DATE,	UPWRITER_ID
FROM BIZ_LIC
WHERE MASTER_NO = #{masterNo}
  AND TASK_TYPE = #{taskType}
  AND TASK_CODE = #{taskCode}

